# ANTI-PATTERN: Single agent handling all cricket match decisions with no specialization
class CricketMatchAgent_Bad:
    def __init__(self, llm):
        self.llm = llm
        self.tools = [
            'check_pitch_condition',
            'analyze_batter_stats',
            'simulate_bowling_option',
            'calculate_field_placement',
            'decide_drs_appeal',
            'manage_powerplay_strategy',
            'optimize_death_bowling'
        ]

    def decide_next_action(self, match_state):
        # Single agent reasoning over 7 unrelated concerns = slow, error-prone
        response = self.llm.query(
            f"Given match state {match_state}, decide: field placement, bowling change, DRS, and powerplay tactics",
            tools=self.tools
        )
        return response

# BEST PRACTICE: Hybrid orchestration with specialized agents and reactive fast-path
class CricketMatchAgent_Good:
    def __init__(self, llm):
        self.llm = llm
        # Reactive agent for high-frequency, low-uncertainty decisions
        self.field_agent = FieldPlacementAgent(llm, tools=['check_pitch_condition', 'analyze_batter_stats'])
        # Deliberative agent for strategic, high-stakes decisions
        self.strategy_agent = StrategicDecisionAgent(llm, tools=['simulate_bowling_option', 'calculate_win_probability'])
        self.drs_confidence_threshold = 0.72

    def decide_next_action(self, match_state):
        # Fast path: routine field decisions reactive
        if match_state['phase'] == 'powerplay':
            field = self.field_agent.decide_field(match_state)  # 100ms, 50 tokens
            return field

        # Deliberative path: strategic escalation on uncertainty
        bowling_confidence = self._estimate_confidence(match_state)
        if bowling_confidence < self.drs_confidence_threshold:
            decision = self.strategy_agent.deliberate(match_state)  # 2s, 2000 tokens
        else:
            decision = self.field_agent.quick_decision(match_state)  # 200ms, 100 tokens

        return decision

    def _estimate_confidence(self, match_state):
        return match_state.get('overs_remaining') / match_state.get('total_overs')

# BEST PRACTICE: Explicit agent specialization and state handoff
class FieldPlacementAgent:
    def __init__(self, llm, tools):
        self.llm = llm
        self.tools = tools
        self.response_budget = 100  # tokens

    def decide_field(self, match_state):
        return self.llm.query(
            f"Based on batter analysis and pitch, suggest field placement",
            tools=self.tools,
            max_tokens=self.response_budget
        )

class StrategicDecisionAgent:
    def __init__(self, llm, tools):
        self.llm = llm
        self.tools = tools
        self.response_budget = 2000  # Extended reasoning

    def deliberate(self, match_state):
        # Receive context from prior agent, add only strategic reasoning
        return self.llm.query(
            f"Given current match state and field setup, recommend bowling change or DRS appeal with confidence scores",
            tools=self.tools,
            max_tokens=self.response_budget,
            reasoning_effort='high'  # Enable extended thinking for high-stakes decisions
        )

# Production-grade hybrid cricket analytics agent
from dataclasses import dataclass
from enum import Enum
import time

class AgentMode(Enum):
    REACTIVE = "reactive"
    DELIBERATIVE = "deliberative"
    HYBRID = "hybrid"

@dataclass
class CricketAgentState:
    player_name: str
    current_role: str  # batsman, bowler, fielder
    match_phase: str   # powerplay, middle, death
    recent_metrics: dict
    cached_decisions: dict
    reasoning_depth: int
    mode: AgentMode

class ProductionCricketAgent:
    def __init__(self, mode=AgentMode.HYBRID):
        self.mode = mode
        self.state = None
        self.tool_latency_budget = 0.1  # 100ms max for reactive

    def decide_shot(self, ball_info: dict) -> str:
        """Route decision based on complexity and time budget."""

        if self.mode == AgentMode.REACTIVE:
            return self._reactive_shot_decision(ball_info)

        elif self.mode == AgentMode.DELIBERATIVE:
            return self._deliberative_shot_decision(ball_info)

        else:  # HYBRID
            # Assess query complexity
            complexity = self._assess_complexity(ball_info)

            if complexity < 0.4:  # Simple situation
                return self._reactive_shot_decision(ball_info)
            elif complexity < 0.7:  # Medium complexity
                return self._hybrid_shot_decision(ball_info, depth=2)
            else:  # High complexity (death overs, pressure situation)
                return self._deliberative_shot_decision(ball_info)

    def _reactive_shot_decision(self, ball_info: dict) -> str:
        """Fast pattern matching against cached decision trees."""
        ball_length = ball_info.get('length')
        ball_line = ball_info.get('line')

        # Cached patterns from recent_metrics
        if ball_length == 'short' and ball_line == 'leg':
            return 'pull'
        elif ball_length == 'full' and ball_line == 'off':
            return 'drive'
        else:
            return 'defend'

    def _deliberative_shot_decision(self, ball_info: dict) -> str:
        """Comprehensive analysis with planning."""
        # Tool integration: field analysis, bowler patterns, match situation
        field_gaps = self._call_tool('analyze_field_gaps')
        bowler_stats = self._call_tool('fetch_bowler_patterns')
        match_context = self._call_tool('get_match_state')

        # Reasoning cycle
        options = ['drive', 'pull', 'leave', 'defend']
        scores = self._evaluate_options(options, field_gaps, bowler_stats, match_context)

        return max(scores, key=scores.get)

    def _hybrid_shot_decision(self, ball_info: dict, depth: int = 2) -> str:
        """Limited deliberation with reactive fallback."""
        # Start reactive, enhance with 1-2 tool calls
        initial_shot = self._reactive_shot_decision(ball_info)

        # Validate with selected tools
        field_gaps = self._call_tool('analyze_field_gaps', timeout=0.05)
        match_state = self._call_tool('get_match_state', timeout=0.05)

        # Adjust reactive choice based on context
        if match_state.get('phase') == 'death' and initial_shot == 'defend':
            return 'aggressive_shot'  # Override in death overs

        return initial_shot

    def _assess_complexity(self, ball_info: dict) -> float:
        """0.0-1.0 complexity score."""
        # Complexity factors
        field_density = ball_info.get('fielders_nearby', 0) / 11
        phase_factor = 0.8 if self.state.match_phase == 'death' else 0.3
        pressure_factor = self.state.recent_metrics.get('run_rate_required', 0) / 10

        return min(1.0, (field_density + phase_factor + pressure_factor) / 3)

    def _call_tool(self, tool_name: str, timeout: float = 1.0) -> dict:
        """Execute tool with timeout protection."""
        start = time.time()
        try:
            if tool_name == 'analyze_field_gaps':
                return {'gaps': ['mid-wicket', 'square-leg'], 'risk': 'low'}
            elif tool_name == 'fetch_bowler_patterns':
                return {'strength': 'yorkers', 'weakness': 'short-ball'}
            elif tool_name == 'get_match_state':
                return {'phase': self.state.match_phase, 'overs_remaining': 6}
        except Exception as e:
            print(f"Tool {tool_name} failed: {e}")
            return {}
        finally:
            elapsed = time.time() - start
            if elapsed > timeout:
                print(f"Warning: {tool_name} exceeded {timeout}s budget")

    def _evaluate_options(self, options: list, field_gaps: dict, 
                         bowler_stats: dict, match_context: dict) -> dict:
        """Score each option based on context."""
        scores = {}
        for option in options:
            score = 0.5  # baseline
            if option in ['drive', 'pull'] and field_gaps.get('gaps'):
                score += 0.3
            if option != bowler_stats.get('strength'):
                score += 0.2
            if match_context.get('phase') == 'death' and option in ['drive', 'pull']:
                score += 0.2
            scores[option] = score
        return scores

# Usage
agent = ProductionCricketAgent(mode=AgentMode.HYBRID)
ball = {'length': 'full', 'line': 'off', 'fielders_nearby': 4}
shot = agent.decide_shot(ball)
print(f"Recommended shot: {shot}")
